//! bench — Benchmark micro-model templates against their few-shot examples.
//! Measures: accuracy (does output contain expected?), latency, token throughput.

use std::time::Instant;

use super::registry::MicroRegistry;
use super::runner::{run_micro, Budget, CircuitBreaker};
use super::validate::quick_validate;
use crate::cluster::Cluster;

/// Result of benchmarking one template.
#[derive(Debug)]
pub struct BenchResult {
    pub template_id: String,
    pub name: String,
    pub tier: String,
    pub few_shot_count: usize,
    pub passed: usize,
    pub failed: usize,
    pub errors: usize,
    pub avg_duration_ms: u64,
    pub total_tokens: u64,
    pub details: Vec<BenchDetail>,
}

/// Detail for one few-shot example run.
#[derive(Debug)]
pub struct BenchDetail {
    pub input: String,
    pub expected: String,
    pub got: String,
    pub matched: bool,
    pub valid: bool,
    pub duration_ms: u64,
}

/// Benchmark all templates that have few-shot examples.
pub fn run_bench(registry: &MicroRegistry, cluster: &Cluster) -> Vec<BenchResult> {
    let mut results = Vec::new();

    let mut templates: Vec<_> = registry.all();
    templates.sort_by_key(|t| t.id.clone());

    for template in templates {
        if template.few_shot.is_empty() {
            continue;
        }

        let mut passed = 0usize;
        let mut failed = 0usize;
        let mut errors = 0usize;
        let mut total_duration_ms = 0u64;
        let mut total_tokens = 0u64;
        let mut details = Vec::new();

        eprintln!(
            "[bench] {} ({}) — {} examples",
            template.name,
            template.id,
            template.few_shot.len()
        );

        for (input, expected) in &template.few_shot {
            let breaker = CircuitBreaker::new(3);
            let budget = Budget::new(100_000);
            let start = Instant::now();

            match run_micro(template, input, cluster, &breaker, &budget) {
                Ok(result) => {
                    let duration_ms = start.elapsed().as_millis() as u64;
                    total_duration_ms += duration_ms;

                    let est_tokens = (result.response.len() / 4) as u64;
                    total_tokens += est_tokens;

                    let response_lower = result.response.trim().to_lowercase();
                    let expected_lower = expected.trim().to_lowercase();
                    let matched = response_lower.contains(&expected_lower)
                        || expected_lower.contains(&response_lower);
                    let valid = quick_validate(&result.response);

                    if matched {
                        passed += 1;
                        eprintln!("  PASS  {:>5}ms  {}", duration_ms, input);
                    } else {
                        failed += 1;
                        eprintln!(
                            "  FAIL  {:>5}ms  {} → got: {}",
                            duration_ms,
                            input,
                            result.response.trim().chars().take(60).collect::<String>()
                        );
                    }

                    details.push(BenchDetail {
                        input: input.clone(),
                        expected: expected.clone(),
                        got: result.response,
                        matched,
                        valid,
                        duration_ms,
                    });
                }
                Err(e) => {
                    let duration_ms = start.elapsed().as_millis() as u64;
                    total_duration_ms += duration_ms;
                    errors += 1;
                    eprintln!("  ERR   {:>5}ms  {} — {}", duration_ms, input, e);

                    details.push(BenchDetail {
                        input: input.clone(),
                        expected: expected.clone(),
                        got: format!("ERROR: {}", e),
                        matched: false,
                        valid: false,
                        duration_ms,
                    });
                }
            }
        }

        let count = template.few_shot.len() as u64;
        let avg_duration_ms = if count > 0 {
            total_duration_ms / count
        } else {
            0
        };

        results.push(BenchResult {
            template_id: template.id.clone(),
            name: template.name.clone(),
            tier: template.tier.clone(),
            few_shot_count: template.few_shot.len(),
            passed,
            failed,
            errors,
            avg_duration_ms,
            total_tokens,
            details,
        });
    }

    results
}

/// Print bench results as a summary table.
pub fn print_bench_results(results: &[BenchResult]) {
    println!("\nMicro-Model Benchmark Results");
    println!("─────────────────────────────────────────────────────────────────");
    println!(
        "{:<12} {:<18} {:<8} {:>5} {:>5} {:>5} {:>5} {:>8}",
        "ID", "Name", "Tier", "Total", "Pass", "Fail", "Err", "Avg(ms)"
    );
    println!("─────────────────────────────────────────────────────────────────");

    let mut total_pass = 0;
    let mut total_fail = 0;
    let mut total_err = 0;
    let mut total_examples = 0;

    for r in results {
        total_pass += r.passed;
        total_fail += r.failed;
        total_err += r.errors;
        total_examples += r.few_shot_count;

        let status = if r.failed == 0 && r.errors == 0 {
            "PASS"
        } else {
            "FAIL"
        };

        println!(
            "{:<12} {:<18} {:<8} {:>5} {:>5} {:>5} {:>5} {:>8} {}",
            r.template_id,
            r.name,
            r.tier,
            r.few_shot_count,
            r.passed,
            r.failed,
            r.errors,
            r.avg_duration_ms,
            status
        );
    }

    println!("─────────────────────────────────────────────────────────────────");
    let accuracy = if total_examples > 0 {
        (total_pass as f64 / total_examples as f64) * 100.0
    } else {
        0.0
    };
    println!(
        "Total: {} examples, {} pass, {} fail, {} errors — {:.0}% accuracy",
        total_examples, total_pass, total_fail, total_err, accuracy
    );
}
